UPDATE IO
SET IO_LOT = #{ioLot}
WHERE IO_ID = #{ioId}

update lot
set
lot_vendor = #{ioVendor},
lot_etw = #{ioDate},
lot_exp = (
SELECT #{ioDate} + ITEM_USEDATE
FROM ITEM
WHERE ITEM_ID = #{itemId}
),
lot_memo = #{ioMsg},
lot_bwhsec = #{whSec}
where lot_id = #{ioLot}

mapper.select:
SELECT vendor_type
FROM vendor
WHERE vendor_id = #{vendorId}

mapper.update:
MERGE INTO STOCK S USING ( SELECT #{itemId} AS ITEM_ID FROM dual ) D ON (S.STOCK_ITEM = D.ITEM_ID)
WHEN MATCHED THEN UPDATE SET S.STOCK_PREV_QTY = NVL(S.STOCK_PREV_QTY, 0) + #{ioQty}
WHEN NOT MATCHED THEN INSERT ( STOCK_ID, STOCK_ITEM, STOCK_PREV_QTY, STOCK_AVAIL_QTY, STOCK_RESERVE_QTY ) VALUES ( 'STOCK' || STOCK_SEQ.NEXTVAL, #{itemId}, #{ioQty}, 0, 0 )

UPDATE STOCK
SET
STOCK_PREV_QTY = STOCK_PREV_QTY - #{ioQty},
STOCK_AVAIL_QTY = STOCK_AVAIL_QTY - #{ioQty}
WHERE STOCK_ITEM = #{itemId}
AND
STOCK_AVAIL_QTY >= #{ioQty}
